"use client"

import { useEffect, useRef, useState } from "react"
import styles from "@/styles/custom-cursor.module.css"

export default function CustomCursor() {
  const [cursorPosition, setCursorPosition] = useState({ x: 0, y: 0 })       // For the big circle (animated)
  const [immediatePosition, setImmediatePosition] = useState({ x: 0, y: 0 }) // For the little dot (exact)
  const [hidden, setHidden] = useState(true)
  const [clicked, setClicked] = useState(false)
  const [linkHovered, setLinkHovered] = useState(false)
  
  // Ref to store the target position for the animation (big circle)
  const targetPosition = useRef({ x: 0, y: 0 })

  // Lerp function for smooth interpolation
  const lerp = (start, end, factor) => start + (end - start) * factor

  useEffect(() => {
    // Animation loop to update the big circle position gradually
    let animationFrameId
    const updateCursor = () => {
      setCursorPosition(prev => {
        const newX = lerp(prev.x, targetPosition.current.x, 0.1)
        const newY = lerp(prev.y, targetPosition.current.y, 0.1)
        return { x: newX, y: newY }
      })
      animationFrameId = requestAnimationFrame(updateCursor)
    }
    updateCursor()
    
    return () => cancelAnimationFrame(animationFrameId)
  }, [])

  useEffect(() => {
    const onMouseMove = (e) => {
      const { clientX, clientY } = e
      // Update target for the animation (big circle)
      targetPosition.current = { x: clientX, y: clientY }
      // Update immediate position for the little dot
      setImmediatePosition({ x: clientX, y: clientY })
    }
    const onMouseEnter = () => setHidden(false)
    const onMouseLeave = () => setHidden(true)
    const onMouseDown = () => setClicked(true)
    const onMouseUp = () => setClicked(false)

    const addEventListeners = () => {
      document.addEventListener("mousemove", onMouseMove)
      document.addEventListener("mouseenter", onMouseEnter)
      document.addEventListener("mouseleave", onMouseLeave)
      document.addEventListener("mousedown", onMouseDown)
      document.addEventListener("mouseup", onMouseUp)
    }

    const removeEventListeners = () => {
      document.removeEventListener("mousemove", onMouseMove)
      document.removeEventListener("mouseenter", onMouseEnter)
      document.removeEventListener("mouseleave", onMouseLeave)
      document.removeEventListener("mousedown", onMouseDown)
      document.removeEventListener("mouseup", onMouseUp)
    }

    addEventListeners()

    // Handle link hover events
    const handleLinkHoverEvents = () => {
      document.querySelectorAll("a, button").forEach((el) => {
        el.addEventListener("mouseenter", () => setLinkHovered(true))
        el.addEventListener("mouseleave", () => setLinkHovered(false))
      })
    }
    handleLinkHoverEvents()

    return () => {
      removeEventListeners()
    }
  }, [])

  // Big circle classes (animated)
  const cursorClasses = `
    ${styles.cursor} 
    ${hidden ? styles.hidden : ""} 
    ${clicked ? styles.clicked : ""} 
    ${linkHovered ? styles.linkHovered : ""}
  `

  // Little dot classes (instant)
  const cursorDotClasses = `
    ${styles.cursorDot} 
    ${hidden ? styles.hidden : ""} 
    ${clicked ? styles.clicked : ""} 
    ${linkHovered ? styles.linkHovered : ""}
  `

  return (
    <>
      {/* Big Circle uses the animated cursorPosition */}
      <div 
        className={cursorClasses} 
        style={{ left: `${immediatePosition.x}px`, top: `${immediatePosition.y}px` }}
      ></div>
      {/* Little Dot uses the immediatePosition */}
      <div 
        className={cursorDotClasses} 
        style={{ left: `${cursorPosition.x}px`, top: `${cursorPosition.y}px` }}
      ></div>
    </>
  )
}
